        class RecognitionRipple {
            constructor(x, y, word = null) {
                this.x = x;
                this.y = y;
                this.age = 0;
                this.maxAge = 200 + Math.random() * 100;
                this.size = 0;
                this.maxSize = 30 + Math.random() * 40;
                this.word = word;
                this.speed = 0.3 + Math.random() * 0.5;
                this.hue = 200 + Math.random() * 60; // blue to purple
