            update() {
                this.age++;
                this.size += this.speed;
                return this.age < this.maxAge;
            }

            draw() {
                const alpha = (1 - this.age / this.maxAge) * 0.5;

                // Draw ripple
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                ctx.strokeStyle = `hsla(${this.hue}, 60%, 70%, ${alpha})`;
                ctx.lineWidth = 1;
                ctx.stroke();

