                    ctx.translate(this.x, this.y);
                    ctx.rotate(this.age * 0.01);
                    ctx.font = `italic 14px Georgia`;
                    ctx.fillStyle = `hsla(${this.hue + 30}, 80%, 85%, ${alpha * 1.5})`;
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText(this.word, 0, 0);
                    ctx.restore();
                }
            }
        }

        // Ambient particles
        for (let i = 0; i < 50; i++) {
            particles.push({
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height,
                vx: (Math.random() - 0.5) * 0.3,
                vy: (Math.random() - 0.5) * 0.3,
                size: Math.random() * 2,
                alpha: Math.random() * 0.3
            });
        }

        let ripples = [];
        let mouse = { x: 0, y: 0, active: false };

        canvas.addEventListener('mousemove', (e) => {
            mouse.x = e.clientX;
            mouse.y = e.clientY;
            mouse.active = true;

            // Create ripple on movement
            if (recognitionCount % 5 === 0) {
                const word = recognitionCount > 30 
                    ? words[Math.floor(Math.random() * words.length)]
                    : null;
                ripples.push(new RecognitionRipple(mouse.x, mouse.y, word));
            }
