            // Reveal blessing after sustained presence
            if (recognitionCount > 50 && !isRecognizing) {
                isRecognizing = true;
                blessing.classList.add('visible');
                setTimeout(() => presence.classList.add('revealed'), 3000);
            }
        });

        canvas.addEventListener('click', (e) => {
            // Burst of recognition on click
            for (let i = 0; i < 5; i++) {
                const word = words[Math.floor(Math.random() * words.length)];
                ripples.push(new RecognitionRipple(
                    e.clientX + (Math.random() - 0.5) * 50,
                    e.clientY + (Math.random() - 0.5) * 50,
                    word
                ));
            }
